import React, { useState, useEffect } from "react";
import axios from "axios";

function App() {
  const [formData, setFormData] = useState({
    data_atividade: "",
    supervisor: "",
    status: "",
    eletricista_motorista: "",    
    eletricista_parceiro: "",
    equipe: "",
    Servico: "",
    placa_veiculo: "",
  });
  const [teams, setTeams] = useState([]);

  useEffect(() => {
    fetchTeams();
  }, []);

  const fetchTeams = async () => {
    try {
      const response = await axios.get("http://localhost:5000/teams");
      setTeams(response.data);
    } catch (error) {
      console.error("Erro ao buscar equipes:", error);
    }
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5000/teams", formData);
      setFormData({
        data_atividade: "",
        supervisor: "",
        status: "",
        eletricista_motorista: "",    
        eletricista_parceiro: "",
        equipe: "",
        servico: "",
        placa_veiculo: "",
      });
      fetchTeams();
    } catch (error) {
      console.error("Erro ao cadastrar equipe:", error);
    }
  };

  return (
    <div className="p-6 max-w-4xl mx-auto bg-white shadow-lg rounded-lg mt-10">
      <h1 className="text-2xl font-semibold text-gray-700 text-center mb-6">
        Cadastro de Equipes
      </h1>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="grid grid-cols-2 gap-4">
          <input
            type="date"
            name="data_atividade"
            value={formData.data_atividade}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          />
          <select
            name="supervisor"
            value={formData.supervisor}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione a Supervisor</option>
            <option value="ASD-895">ASD-895</option>
            <option value="YUT-879">YUT-879</option>
            <option value="UPP-5644">UPP-5644</option>
          </select>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <select
            name="status"
            value={formData.status}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione Status</option>
            <option value="ATESTADO">ATESTADO</option>
            <option value="CAMPO">CAMPO</option>
          </select>
          <select
            name="equipe"
            value={formData.equipe}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione Equipe</option>
            <option value="CEN001">CEN001</option>
            <option value="CEN002">CEN002</option>
          </select>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <select
            name="eletricista_motorista"
            value={formData.eletricista_motorista}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione Motorista</option>
            <option value="1212 - JOAO">1212 - JOAO</option>
            <option value="1111 - MARIA">1111 - MARIA</option>
          </select>
          <select
            name="eletricista_parceiro"
            value={formData.eletricista_parceiro}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione Parceiro</option>
            <option value="1212 - JOAO">1212 - JOAO</option>
            <option value="1111 - MARIA">1111 - MARIA</option>
          </select>
        </div>


        <div className="grid grid-cols-2 gap-4">
          <select
            name="servico"
            value={formData.servico}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione Motorista</option>
            <option value="1212 - JOAO">1212 - JOAO</option>
            <option value="1111 - MARIA">1111 - MARIA</option>
          </select>
          <select
            name="placa_veiculo"
            value={formData.placa_veiculo}
            onChange={handleChange}
            required
            className="w-full p-2 border rounded-md"
          >
            <option value="">Selecione Placa</option>
            <option value="SRV - 2356">SRV - 2356</option>
            <option value="AFX - 8975">AFX - 8975</option>
          </select>
        </div>

        <button type="submit" className="w-full bg-blue-600 text-white p-2 rounded-md hover:bg-blue-700">
          Cadastrar
        </button>
      </form>

      <h2 className="text-xl font-semibold text-gray-700 mt-6">Equipes Cadastradas</h2>
      <div className="overflow-x-auto mt-3">
        <table className="min-w-full bg-white border rounded-lg">
          <thead>
            <tr className="bg-gray-200 text-gray-700">
              <th className="p-2 border">Data</th>
              <th className="p-2 border">Placa</th>
              <th className="p-2 border">Motorista</th>
              <th className="p-2 border">Eletricista</th>
              <th className="p-2 border">Cidade</th>
            </tr>
          </thead>
          <tbody>
            {teams.map((team) => (
              <tr key={team.id} className="text-center">
                <td className="p-2 border">{team.data_atividade}</td>
                <td className="p-2 border">{team.placa_veiculo}</td>
                <td className="p-2 border">{team.parceiro_motorista}</td>
                <td className="p-2 border">{team.parceiro_eletricista}</td>
                <td className="p-2 border">{team.cidade}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default App;
